module RefModule (
    input [3:0] A,
    input [3:0] B,
    output [3:0] SUM,
    output COUT
);
    wire [3:0] obf_G; // Generate
    wire [3:0] P; // Propagate
    wire [4:0] C; // Carry

    assign obf_G = A & B; // Generate
    assign P = A ^ B; // Propagate

    assign C[0] = 0; // C0 is 0
    assign C[1] = obf_G[0] | (P[0] & C[0]);
    assign C[2] = obf_G[1] | (P[1] & obf_G[0]) | (P[1] & P[0] & C[0]);
    assign C[3] = obf_G[2] | (P[2] & obf_G[1]) | (P[2] & P[1] & obf_G[0]) | (P[2] & P[1] & P[0] & C[0]);
    assign C[4] = obf_G[3] | (P[3] & obf_G[2]) | (P[3] & P[2] & obf_G[1]) | (P[3] & P[2] & P[1] & obf_G[0]) | (P[3] & P[2] & P[1] & P[0] & C[0]);

    assign SUM = P ^ C[3:0]; // Sum calculation
    assign COUT = C[4]; // Carry out

endmodule
